    # Mapping of opening to closing bracket types for easy lookup
    matching_brackets = {')': '(', '}': '{', ']': '['}

    # Iterate through the string character by character
    for char in expression:
        if char in "({[":  # If it's an opening bracket, push to stack
            stack.append(char)
        elif char in ")}]":  # If it's a closing bracket and matches the last opened one (if any), pop from stack
            try:
                if not stack or matching_brackets[stack[-1] != char:
                    return False  # Mismatched brackets, invalid string
                stack.pop()  # Match found, remove it from the stack
            except IndexError:
                return False  # Stack is empty when trying to pop
        else:
            continue  # Ignore other characters for now (like letters or digits)

    return not stack  # If stack is empty at the end, all brackets were matched and valid

